  ('dietitian-moex-09664', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '催化lipoprotein如chylomicron中之三酸甘油酯（triglyceride）水解為free fatty acid的lipoprotein lipase， 其活性受何種荷爾蒙所促進？', '["glucagon", "insulin", "epinephrine", "cortisol"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "de43fc821d8d", "answer_pdf_sha1": "68b07f35fdf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09665', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關胺基酸之敘述，何者錯誤？', '["arginine為一種鹼性胺基酸", "tyrosine可由phenylalanine代謝轉變而合成，故非為essential amino acid", "trypsin可水解arginine和leucine之C terminal peptide bond", "米的蛋白質的1 st limiting amino acid為lysine"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "de43fc821d8d", "answer_pdf_sha1": "68b07f35fdf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09666', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', 'Pyridoxine coenzyme參與何種生化代謝？', '["acyl-group transfer", "amino-group transfer", "carboxyl-group transfer", "hydrogen-atom transfer"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "de43fc821d8d", "answer_pdf_sha1": "68b07f35fdf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09667', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關酮體（ketone bodies）之敘述，何者正確？', '["由肝臟所合成，可在hepatocytes經代謝再利用", "可由於飲食中不足的carbohydrate，使cholesterol異常代謝而產生", "在肝臟中合成，而在extrahepatic tissue中被代謝利用", "包括acetoacetic acid、β-hydroxyisobutyric acid和acetone，後者不能被利用而經由肺和腎排出"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "de43fc821d8d", "answer_pdf_sha1": "68b07f35fdf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09668', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '乳糖不耐症（lactose intolerance）嚴重時會造成腹瀉，過多的水分留在腸腔最主要是因為：', '["牛奶造成小腸腸腔內液成為低張溶液", "未消化且不能吸收的乳糖在腸腔形成滲透壓效應", "乳糖在腸腔形成低張溶液", "牛奶中的蛋白質在腸腔中形成膠體滲透壓"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09669', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '糖尿病的病人，若血糖控制不好、太高，會出現糖尿。下列何者與葡萄糖之出現在尿中最相關？', '["近曲小管之葡萄糖次級主動運輸（secondary active transport）有最大運送量能（transport maximum）", "遠曲小管、集尿管以主動運輸再吸收葡萄糖，多餘的會出現在尿中", "遠曲小管、集尿管以促進性擴散吸收葡萄糖，無法全部吸收", "糖在尿中使尿的滲透壓大過於血漿，不容易再吸收"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09670', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於脂肪的消化，下列敘述何者正確？', '["游離溶解於腸液中的脂肪酸及單酸甘油脂（monoglyceride），可靠擴散通過腸黏膜表皮細胞的細胞膜", "經膽汁乳膠化（emulsified）的脂肪小滴（lipid droplets），可靠擴散通過腸黏膜表皮細胞的細胞膜", "小腸脂肪酵素（lipase）為脂溶性，可進入脂肪小滴進行分解消化作用", "被吸收的脂肪酸及單酸甘油脂，在乳糜管（lacteal ducts）重新組合成脂肪小滴"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09671', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於維生素B 的吸收，下列何者正確？ 12', '["為水溶性，在小腸經擴散吸收", "缺乏此維生素，會造成貧血，病人紅血球體積小但數目多", "胃以主動運輸方式吸收它", "胃大部分被切除之病人，容易造成此維生素缺乏"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09672', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於胃的功能，下列敘述何者正確？', '["壁細胞（parietal cells）分泌胃泌素（gastrin）", "在頭期（cephalic phase），主細胞（chief cells）胃酸分泌增加，主要由乙醯膽鹼（acetylcholine）促進", "嚴重的嘔吐，除了損失胃酸，可能造成鹼中毒，也會造成鉀過度流失，引起低血鉀症狀", "組織胺（histamine）是抑制胃酸分泌的重要因素"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09673', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於膽汁的分泌，下列敘述何者正確？', '["由膽囊的表皮細胞分泌", "由膽囊的腺細胞分泌", "與消化脂肪有關的，主要是膽鹽", "與消化脂肪有關的，主要是膽色素"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
